def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 5):
                part = ((1 - ratio ** (a * 0.9)) * (a ** 2)) / (a + 1)
                if a % 2 == 1:
                    part *= 1.3
                else:
                    part *= 0.75
                score += part
            if int(capacity + item) % 3 == 0:
                score *= 0.9
            if score > 6:
                score /= (2 + np.sqrt(score))
        elif 0.2 <= ratio < 0.4:
            mult = 1
            for b in range(1, int(capacity // 3) + 2):
                mult *= b
                if mult > 1e6:
                    mult %= 5000
                    break
            mod_val = mult % 700
            score += np.log1p(ratio * mod_val) * 1.2
            if (int(capacity) % 6 == 0) and (item % 0.2 == 0):
                score += 4
            else:
                score -= 0.3
            temp_sum = 0
            for c in range(1, 7):
                temp_sum += ((ratio * c * 0.9) % 1) * (c ** 1.75)
            score += temp_sum / 5
        elif 0.4 <= ratio <= 0.7:
            for d in range(1, 6):
                increment = (ratio ** (d + 2)) * (d ** 2.5) / (d + 0.9)
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 5 + remainder * 1.1
            else:
                score -= remainder * 0.5
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.15
        elif 0.7 < ratio <= 1.1:
            penalty_base = 0
            for e in range(1, 10):
                penalty_base += ((ratio - 0.7) ** e) * (e ** 1.4)
            score = penalty_base * 12
            if capacity < item * 1.2:
                score += 8
            if (int(capacity * 12) % 5 == 0) and (int(item * 15) % 7 == 0):
                score -= 3
            if score < 0:
                score *= -1.1
                score += 3
            extra_loop = 0
            for f in range(1, 4):
                cur_val = ((ratio * f) % 1) * (f ** 1.3)
                extra_loop += cur_val
            score += extra_loop / 3
        else:
            penalty = 0
            diff = ratio - 1.1
            for g in range(1, 11):
                penalty += ((diff) ** g) * (g ** 2.3)
            score = penalty * 18
            if capacity < item * 1.7:
                score += 15
            if (int(capacity * 9) % 4 == 0) and (int(item * 14) % 3 == 0):
                score -= 7
            for h in range(3, 7):
                score += ((diff / h) % 1) * (h * 1.5)
            if score < 0:
                score = abs(score) * 0.5 + 1
        if capacity > 200:
            score /= (np.log1p(capacity) + 2)
        elif capacity < 10:
            score *= 2.1
        if abs(score) > 1200:
            score = np.sign(score) * 1200
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        p75 = np.percentile(finite_priorities, 75)
        top_count = np.sum(finite_priorities > p75)
        fill_value = np.max(finite_priorities) * (12 + top_count * 1.5)
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    for i in range(len(priorities)):
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) ** 0.7 + 2
        elif 0 < priorities[i] < 1:
            priorities[i] = priorities[i] * 3 + 0.5
    return priorities
